import { useNavigate } from 'react-router-dom';
import SideBox from '../../component/main-component/SideBox';
import { useAuth } from '../../context/AuthContext';
import { useState } from 'react';



// search page
import FriendSearch from '../friend/FriendSearch';
import FriendList from '../../component/main-component/FriendList';

export default function Main(){
    const navs = useNavigate();
    const { userInfo } = useAuth();

    const [choice, setChoice] =  useState();

    return(
        <main>
            {userInfo ?
                <div style={{display: "flex"}}>
                    <SideBox setChoice = {setChoice}/>
                    {choice === 'chat' ? 
                        <div>
                            <h3>chat</h3>
                        </div> :
                        <div>
                            <div style={{width: "20%"}}>
                                <FriendList />
                            </div>
                            <div>
                                <FriendSearch/>
                            </div>
                        </div>
                    }  
                </div>
                :
                <div>
                    <h2 style={{textAlign: "center", marginTop: "20px"}}>로그인이 필요합니다.</h2>
                </div>
            }
        </main>
    )
}
